**Temporary Bug B integration script (`session-bugb-e2e.test.ts`, not committed)**

This script wires `browser-maintenance` to the real `session-tab-registry` in-memory Map, tracks a tab under the peer-scoped key, runs `initSessionState` with `/new` + direct Telegram ctx, and asserts the registry count drops to 0. The second case shows the old cleanup key list leaves the tab behind until the peer-scoped key is included.

<details>
<summary>Full temporary integration script</summary>

```typescript
/**
 * Bug B end-to-end integration test (temporary proof script; not committed to repo).
 *
 * Verifies that browser tabs tracked with a peer-scoped sandboxSessionKey
 * (e.g. "agent:main:telegram:default:direct:12345") are correctly found and
 * removed from the registry when /new triggers cleanupBrowserSessionsForLifecycleEnd.
 */
import fs from "node:fs/promises";
import os from "node:os";
import path from "node:path";
import { afterAll, afterEach, beforeAll, beforeEach, describe, expect, it, vi } from "vitest";
import type { OpenClawConfig } from "../../config/config.js";
import type { SessionEntry } from "../../config/sessions.js";

const sessionForkMocks = vi.hoisted(() => ({
  forkSessionFromParent: vi.fn(),
  resolveParentForkTokenCount: vi.fn(),
  nextSessionId: 0,
}));
const channelSummaryMocks = vi.hoisted(() => ({
  buildChannelSummary: vi.fn(async () => [] as string[]),
}));

vi.mock("./session-fork.js", () => ({
  forkSessionFromParent: (...args: unknown[]) => sessionForkMocks.forkSessionFromParent(...args),
  resolveParentForkTokenCount: (...args: unknown[]) =>
    sessionForkMocks.resolveParentForkTokenCount(...args),
  resolveParentForkDecision: async (params: { parentEntry: SessionEntry; storePath: string }) => {
    const maxTokens = 100_000;
    const parentTokens = await sessionForkMocks.resolveParentForkTokenCount({
      parentEntry: params.parentEntry,
      storePath: params.storePath,
    });
    if (typeof parentTokens === "number" && parentTokens > maxTokens) {
      return { status: "skip", reason: "parent-too-large", maxTokens, parentTokens, message: "" };
    }
    return { status: "fork", maxTokens };
  },
}));

vi.mock("../../plugin-sdk/browser-maintenance.js", async () => {
  const registry = await import(
    "../../../extensions/browser/src/browser/session-tab-registry.js"
  );
  return {
    closeTrackedBrowserTabsForSessions: async (
      params: Parameters<typeof registry.closeTrackedBrowserTabsForSessions>[0],
    ) =>
      registry.closeTrackedBrowserTabsForSessions({
        ...params,
        closeTab: async () => {},
      }),
  };
});

vi.mock("../../plugins/hook-runner-global.js", () => ({ getGlobalHookRunner: () => null }));
vi.mock("../../infra/channel-summary.js", () => ({
  buildChannelSummary: channelSummaryMocks.buildChannelSummary,
}));
vi.mock("../../agents/session-write-lock.js", async () => {
  const actual = await vi.importActual<typeof import("../../agents/session-write-lock.js")>(
    "../../agents/session-write-lock.js",
  );
  return {
    ...actual,
    acquireSessionWriteLock: vi.fn(async () => ({ release: async () => {} })),
    resolveSessionLockMaxHoldFromTimeout: vi.fn(
      ({
        timeoutMs,
        graceMs = 2 * 60_000,
        minMs = 5 * 60_000,
      }: {
        timeoutMs: number;
        graceMs?: number;
        minMs?: number;
      }) => Math.max(minMs, timeoutMs + graceMs),
    ),
  };
});
vi.mock("../../agents/model-catalog.js", () => ({
  loadModelCatalog: vi.fn(async () => [
    { provider: "minimax", id: "m2.7", name: "M2.7" },
    { provider: "openai", id: "gpt-5.5", name: "GPT-5.5" },
  ]),
}));

import {
  trackSessionBrowserTab,
  countTrackedSessionBrowserTabsForTests,
  resetTrackedSessionBrowserTabsForTests,
} from "../../../extensions/browser/src/browser/session-tab-registry.js";
import { initSessionState } from "./session.js";

let suiteRoot = "";

beforeAll(async () => {
  suiteRoot = await fs.mkdtemp(path.join(os.tmpdir(), "openclaw-bugb-e2e-"));
});
afterAll(async () => {
  await fs.rm(suiteRoot, { recursive: true, force: true });
});

beforeEach(() => {
  channelSummaryMocks.buildChannelSummary.mockReset().mockResolvedValue([]);
  sessionForkMocks.nextSessionId = 0;
  sessionForkMocks.resolveParentForkTokenCount.mockReset();
  resetTrackedSessionBrowserTabsForTests();
});
afterEach(() => {
  resetTrackedSessionBrowserTabsForTests();
});

async function writeSession(
  storePath: string,
  sessionKey: string,
  entry: Partial<SessionEntry>,
) {
  let store: Record<string, unknown> = {};
  try {
    store = JSON.parse(await fs.readFile(storePath, "utf8"));
  } catch {}
  store[sessionKey] = { sessionId: "prev-session-uuid", updatedAt: Date.now(), ...entry };
  await fs.writeFile(storePath, JSON.stringify(store), "utf8");
}

describe("Bug B E2E: /new cleanup finds peer-scoped tracked tabs", () => {
  it("removes a tab tracked with peer-scoped key when canonical key is agent:main:main", async () => {
    const canonicalKey = "agent:main:main";
    const peerScopedKey = "agent:main:telegram:default:direct:12345";

    const storePath = path.join(suiteRoot, "e2e-bugb-sessions.json");
    await writeSession(storePath, canonicalKey, {});

    trackSessionBrowserTab({ sessionKey: peerScopedKey, targetId: "tab-1" });
    expect(countTrackedSessionBrowserTabsForTests(peerScopedKey)).toBe(1);
    expect(countTrackedSessionBrowserTabsForTests()).toBe(1);

    const cfg: OpenClawConfig = {
      session: { store: storePath, idleMinutes: 999 },
    } as OpenClawConfig;

    const result = await initSessionState({
      ctx: {
        Body: "/new",
        RawBody: "/new",
        CommandBody: "/new",
        From: "12345",
        Provider: "telegram",
        ChatType: "direct",
      },
      cfg,
      commandAuthorized: true,
    });

    expect(result.isNewSession).toBe(true);

    await vi.waitFor(
      () => {
        expect(countTrackedSessionBrowserTabsForTests()).toBe(0);
      },
      { timeout: 2000 },
    );
  });

  it("does NOT remove the tab when cleanup only passes canonical key", async () => {
    const peerScopedKey = "agent:main:telegram:default:direct:99999";
    trackSessionBrowserTab({ sessionKey: peerScopedKey, targetId: "tab-2" });
    expect(countTrackedSessionBrowserTabsForTests(peerScopedKey)).toBe(1);

    const { closeTrackedBrowserTabsForSessions } = await import(
      "../../../extensions/browser/src/browser/session-tab-registry.js"
    );

    await closeTrackedBrowserTabsForSessions({
      sessionKeys: ["prev-session-uuid", "agent:main:main"],
      closeTab: async () => {},
    });

    expect(countTrackedSessionBrowserTabsForTests(peerScopedKey)).toBe(1);

    await closeTrackedBrowserTabsForSessions({
      sessionKeys: ["prev-session-uuid", "agent:main:main", peerScopedKey],
      closeTab: async () => {},
    });

    expect(countTrackedSessionBrowserTabsForTests(peerScopedKey)).toBe(0);
  });
});
```

</details>

